#[inline(always)]
fn read_huff(&mut self, huff: &[u16; 4096]) -> u32 {
    self.fill(12);
    let idx = ((self.buf >> (self.nbits - 12)) & 0xFFF) as usize;
    let entry = huff[idx];
    let len = (entry >> 8) as u32;
    self.nbits -= len;
    (entry & 0xff) as u32
}

